import{a as e,c as t,i as n,n as r,o as i,r as a,s as o,t as s}from"./app-X_Kuuhdi.js";var c=JSON.parse(`{"path":"/design/gerald-genta.html","title":"제럴드 젠타: 럭셔리 스포츠 워치의 창시자","lang":"ko-KR","frontmatter":{"description":"제럴드 젠타: 럭셔리 스포츠 워치의 창시자 Patek Philippe Nautilus Ref. 3700 (1976) Patek Philippe Nautilus, 1976 제럴드 젠타(Gérald Charles Genta, 1931–2011)는 20세기 시계 디자인의 가장 결정적인 인물 중 한 명이다. Royal Oa...","permalink":"/design/gerald-genta","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"제럴드 젠타: 럭셔리 스포츠 워치의 창시자\\",\\"image\\":[\\"https://upload.wikimedia.org/wikipedia/commons/6/6e/Patek-Philippe-Nautilus-3700-1A.jpg\\",\\"https://upload.wikimedia.org/wikipedia/commons/7/74/Patek-Philippe-Nautilus-5711.jpg\\"],\\"dateModified\\":\\"2026-06-12T21:24:01.000Z\\",\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://kmbzn.com/design/gerald-genta"}],["meta",{"property":"og:title","content":"제럴드 젠타: 럭셔리 스포츠 워치의 창시자"}],["meta",{"property":"og:description","content":"제럴드 젠타: 럭셔리 스포츠 워치의 창시자 Patek Philippe Nautilus Ref. 3700 (1976) Patek Philippe Nautilus, 1976 제럴드 젠타(Gérald Charles Genta, 1931–2011)는 20세기 시계 디자인의 가장 결정적인 인물 중 한 명이다. Royal Oa..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://upload.wikimedia.org/wikipedia/commons/6/6e/Patek-Philippe-Nautilus-3700-1A.jpg"}],["meta",{"property":"og:locale","content":"ko-KR"}],["meta",{"property":"og:updated_time","content":"2026-06-12T21:24:01.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-12T21:24:01.000Z"}]]},"git":{"createdTime":1781276034000,"updatedTime":1781299441000,"contributors":[{"name":"kmbzn","username":"kmbzn","email":"kmbzn24@gmail.com","commits":4,"url":"https://github.com/kmbzn"},{"name":"Claude Sonnet 4.6","username":"","email":"noreply@anthropic.com","commits":1}],"changelog":[{"hash":"f6dc71516ce661651824477e87b12a65440654b5","time":1781299441000,"email":"kmbzn24@gmali.com","author":"kmbzn","message":"feat: update site and theme data, enhance design page, and optimize assets"},{"hash":"47b5aed4ca177bf4af7be2a57306ea9a97ab434f","time":1781297335000,"email":"kmbzn24@gmali.com","author":"kmbzn","message":"0613_final"},{"hash":"867901d169b73496a8a67d2853b6d0b27bdbf876","time":1781277144000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"docs: rename all files to lowercase and add Products/Finance articles","coAuthors":[{"name":"Claude Sonnet 4.6","email":"noreply@anthropic.com"}]},{"hash":"e21cf0ebbfdf5b897074fade7d0f32f4e5a2562c","time":1781276034000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"docs: add images to Google redesign article, add Gerald Genta and Bauhaus articles"}]},"filePathRelative":"design/gerald-genta.md","autoDesc":true}`),l={name:`gerald-genta.md`},u={class:`print-section`};function d(s,c,l,d,f,p){let m=t(`DateMeta`);return o(),a(`div`,null,[r(`section`,u,[c[0]||=r(`h1`,{id:`제럴드-젠타-럭셔리-스포츠-워치의-창시자`,tabindex:`-1`},[r(`a`,{class:`header-anchor`,href:`#제럴드-젠타-럭셔리-스포츠-워치의-창시자`},[r(`span`,null,`제럴드 젠타: 럭셔리 스포츠 워치의 창시자`)])],-1),i(m),c[1]||=r(`p`,null,[r(`img`,{src:`https://upload.wikimedia.org/wikipedia/commons/6/6e/Patek-Philippe-Nautilus-3700-1A.jpg`,alt:`Patek Philippe Nautilus Ref. 3700 (1976)`})],-1),c[2]||=r(`blockquote`,null,[r(`p`,null,[r(`em`,null,`Patek Philippe Nautilus, 1976`)])],-1),c[3]||=r(`p`,null,[e(`제럴드 젠타(Gérald Charles Genta, 1931–2011)는 20세기 시계 디자인의 가장 결정적인 인물 중 한 명이다. Royal Oak, Nautilus, IWC Ingenieur 등 오늘날 시계 시장에서 가장 높은 가격을 형성하는 스포츠 워치 카테고리가 모두 그의 손에서 탄생했다. 그는 단순히 시계를 디자인한 것이 아니라, `),r(`strong`,null,`럭셔리 스포츠 워치`),e(`라는 장르 자체를 발명했다.`)],-1)]),c[4]||=n(`<section class="print-section"><h2 id="생애" tabindex="-1"><a class="header-anchor" href="#생애"><span>생애</span></a></h2><p>1931년 5월 1일, 스위스 제네바에서 스위스인 어머니와 이탈리아 피에몬테 출신 아버지 사이에서 태어났다. 20세에 스위스 연방 금세공사 자격증을 취득하고, 이후 독립 디자이너로 활동하며 IWC, Omega, Universal Genève, Patek Philippe, Audemars Piguet 등 거의 모든 주요 시계 브랜드와 협업했다.</p><p>평생 10만 건 이상의 디자인을 남긴 것으로 알려져 있으며, 정작 본인은 손목시계를 착용하지 않았다고 전해진다. 2011년 8월 17일, 80세의 나이로 별세했다.</p></section><section class="print-section"><h2 id="주요-작품" tabindex="-1"><a class="header-anchor" href="#주요-작품"><span>주요 작품</span></a></h2></section><section class="print-section"><h3 id="universal-geneve-polerouter-1954" tabindex="-1"><a class="header-anchor" href="#universal-geneve-polerouter-1954"><span>Universal Genève Polerouter (1954)</span></a></h3><p>젠타의 첫 번째 대형 성공작. 23세의 나이에 SAS 항공사를 위해 디자인했으며, 세계 최초의 상업용 마이크로로터 무브먼트를 탑재한 시계였다. 얇고 우아한 케이스에 자동 와인딩을 구현한 이 시계는 당시 기술적·미적으로 모두 획기적이었다.</p></section><section class="print-section"><h3 id="audemars-piguet-royal-oak-1970" tabindex="-1"><a class="header-anchor" href="#audemars-piguet-royal-oak-1970"><span>Audemars Piguet Royal Oak (1970)</span></a></h3><p>젠타의 가장 유명한 작품이자, <strong>세계 최초의 럭셔리 스포츠 워치</strong>로 평가받는다.</p><p>1970년, Audemars Piguet의 경영진은 쿼츠 쇼크로 흔들리는 시장에서 돌파구를 찾기 위해 젠타에게 연락했다. 그는 단 하룻밤 만에 디자인 스케치를 완성했다고 알려져 있다. 영감의 원천은 잠수함의 해치(porthole)였다. 팔각형의 베젤과 드러난 나사, 그리고 케이스와 브레이슬릿이 하나로 통합된 구조였다.</p><p>1972년 바젤 페어에서 공개되었을 때 반응은 냉담했다. 스테인리스 스틸 소재에, 당시 기준으로 충격적인 고가(약 3,300 스위스 프랑)는 &quot;왜 철제 시계에 금시계 값을?&quot;이라는 비판을 받았다. 하지만 Royal Oak은 정확히 그 논리를 뒤집었다. 스틸이라서 비싼 것이 아니라, <strong>디자인과 무브먼트의 완성도</strong>가 가격을 결정한다는 새로운 패러다임을 제시했다.</p><p>오늘날 Royal Oak은 Audemars Piguet의 상징이자 중고 시장에서 정가를 크게 웃도는 시계 중 하나다.</p><p><strong>주요 스펙 (Ref. 5402 오리지널 기준)</strong></p><ul><li>케이스: 39mm, 스테인리스 스틸</li><li>팔각형 베젤, 8개의 육각 나사</li><li>다이얼: &quot;Grande Tapisserie&quot; 패턴</li><li>무브먼트: Cal. 2121 (Jaeger-LeCoultre 기반)</li></ul></section><section class="print-section"><h3 id="patek-philippe-nautilus-1976" tabindex="-1"><a class="header-anchor" href="#patek-philippe-nautilus-1976"><span>Patek Philippe Nautilus (1976)</span></a></h3><p>Royal Oak의 성공에 자극을 받은 Patek Philippe가 젠타에게 같은 방향의 디자인을 의뢰했다. 그는 대서양 정기선의 현창(porthole)에서 영감을 얻어 Nautilus를 설계했다.</p><p><img src="https://upload.wikimedia.org/wikipedia/commons/7/74/Patek-Philippe-Nautilus-5711.jpg" alt="Patek Philippe Nautilus Ref. 5711"></p><p>Nautilus는 Royal Oak과 비교해 보다 수평적이고 유선형인 케이스가 특징이다. 가로로 늘어난 팔각형 베젤, 수평 엠보싱 다이얼, 통합 브레이슬릿이 독자적인 정체성을 만들었다.</p><p>오리지널 Ref. 3700은 당시에도 논란이 있었지만, 이후 Ref. 5711이 단종(2021년)된 직후 중고가가 정가의 3–4배로 폭등하면서 시계 역사상 가장 투기적인 모델 중 하나로 기록되었다.</p><p><strong>주요 스펙 (Ref. 3700 오리지널 기준)</strong></p><ul><li>케이스: 42mm × 27mm, 스테인리스 스틸</li><li>방수: 120m</li><li>무브먼트: Cal. 28-255 C</li></ul></section><section class="print-section"><h3 id="iwc-ingenieur-sl-1976" tabindex="-1"><a class="header-anchor" href="#iwc-ingenieur-sl-1976"><span>IWC Ingenieur SL (1976)</span></a></h3><p>Royal Oak, Nautilus와 같은 해에 발표된 또 하나의 젠타 작품. IWC Ingenieur SL(Ref. 1832)은 기술적 콘셉트에 기반한 스포츠 워치로, 내부에 순철 케이스를 삽입해 자기장을 차폐하는 방자성(antimagnetic) 구조가 핵심이었다.</p><p>&quot;Jumbo&quot;라는 별명으로 불렸으며, 당시로서는 큰 40mm 케이스, 5개의 오목 홈이 있는 베젤, H-링크 브레이슬릿이 특징이다. 상업적으로는 1,000여 점만 생산되어 지금은 희귀한 컬렉터 아이템이 되었다.</p></section><section class="print-section"><h2 id="디자인-철학" tabindex="-1"><a class="header-anchor" href="#디자인-철학"><span>디자인 철학</span></a></h2><p>젠타가 구사한 핵심 언어는 일관되다.</p><p><strong>팔각형 또는 변형된 기하형태의 케이스</strong>: 원형도 직사각형도 아닌 독자적인 형태로 즉각적인 식별성을 만들었다.</p><p><strong>통합 브레이슬릿</strong>: 케이스와 브레이슬릿의 경계를 없애 시계를 손목의 일부처럼 보이게 했다. 이것은 당시로서는 급진적 선택이었다.</p><p><strong>드러난 나사</strong>: 기능적 요소를 장식으로 전환한 대표적 사례. 이전까지 나사는 숨기는 것이 당연했다.</p><p><strong>스테인리스 스틸의 재평가</strong>: 귀금속이 아닌 스틸을 최고급 소재로 포지셔닝한 것은 시장의 고정관념을 정면으로 깨는 시도였다.</p><p>이 언어들은 지금도 수많은 스포츠 워치 디자인의 문법으로 남아 있다.</p></section><section class="print-section"><h2 id="유산" tabindex="-1"><a class="header-anchor" href="#유산"><span>유산</span></a></h2><p>젠타는 브랜드 종속 없이 독립 디자이너로 활동했다. 그가 남긴 디자인들은 단순히 잘 팔린 시계가 아니라, 시계 시장의 <strong>카테고리 자체를 재정의</strong>했다. 그 이전까지 고급 시계는 정장에 어울리는 드레스 워치였다. 젠타 이후, 청바지에 매치하는 스포츠 워치도 최상위 럭셔리로 인정받게 되었다.</p><p>오늘날 Royal Oak과 Nautilus의 대기 수요와 중고 프리미엄은, 한 디자이너의 결정이 반세기 후에도 시장을 지배할 수 있다는 것을 증명한다.</p><p><em>이미지 출처: Wikimedia Commons, CC BY-SA 4.0</em></p></section>`,8)])}var f=s(l,[[`render`,d]]);export{c as _pageData,f as default};